public class Hanoi {
    static int moves = 0;
    static void hanoi(int n, char from, char to, char aux) {
        if (n == 0) return;
        hanoi(n - 1, from, aux, to);
        moves++;
        hanoi(n - 1, aux, to, from);
    }
    public static void main(String[] args) {
        hanoi(3, 'A', 'C', 'B');
        System.out.println(moves);
        moves = 0;
        hanoi(4, 'A', 'C', 'B');
        System.out.println(moves);
    }
}
